// Two-layer validation (A9/A12). Layer 1: parse the raw body inside a
// code-controlled try/catch, so a malformed payload throws inside code
// we control, not n8n's own parsing layer.

let parsed;
try {
  parsed = JSON.parse($json.body || '{}');
} catch (e) {
  return [{ json: { valid: false, status: 400, reason: 'malformed_json' } }];
}

// Project identifier validated against the active-project index BEFORE
// any file path is ever constructed from it -- closes the
// Working\undefined\schema.json class of failure.
const fs = require('fs');
const path = require('path');
let activeProjects = [];
try { activeProjects = JSON.parse(fs.readFileSync(path.join('Shared', 'processed_projects.json'), 'utf8')); } catch (e) {}

const prefix = parsed.project_prefix;
if (!prefix || typeof prefix !== 'string' || !activeProjects.includes(prefix)) {
  return [{ json: { valid: false, status: 400, reason: 'invalid_or_missing_project_prefix' } }];
}

return [{ json: { valid: true, project_prefix: prefix, payload: parsed } }];

// Schema read with retry-with-backoff -- tolerant of any transient
// host-level file lock (antivirus sweep, indexing), never a single
// unbuffered attempt (A9/A12).
const fs = require('fs');
const path = require('path');
const schemaPath = path.join('Working', $json.project_prefix, 'intake_schema.json');

let schema = null;
let lastErr = null;
for (let attempt = 0; attempt < 3; attempt++) {
  try {
    schema = JSON.parse(fs.readFileSync(schemaPath, 'utf8'));
    break;
  } catch (e) {
    lastErr = e;
    const wait = 50 * (attempt + 1);
    const start = Date.now();
    while (Date.now() - start < wait) { /* brief spin, ~50-150ms total */ }
  }
}

if (!schema) {
  return [{ json: { valid: false, status: 400, reason: 'schema_unreadable_after_retry' } }];
}

// Validate submitted fields against the schema's allowlist -- alphanumeric
// + underscore, 40-char cap, blocked from __proto__/constructor/prototype.
const BLOCKED = new Set(['__proto__', 'constructor', 'prototype']);
const submitted = Object.keys($json.payload.fields || {});
const schemaFields = new Set(schema.fields.map(f => f.name));

for (const key of submitted) {
  if (BLOCKED.has(key) || !schemaFields.has(key)) {
    return [{ json: { valid: false, status: 400, reason: 'field_not_in_schema: ' + key } }];
  }
}

return [{ json: { valid: true, project_prefix: $json.project_prefix, payload: $json.payload } }];

// Per-contact-hash lock file (A12). Concurrent request finding a live
// lock aborts rather than racing. Heartbeat-refreshed elsewhere by the
// background job; here we only create/check it.
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const email = ($json.payload.fields && $json.payload.fields.email) || '';
const hash = crypto.createHash('sha256').update(email.toLowerCase().trim()).digest('hex');
const lockPath = path.join('Working', $json.project_prefix, 'locks', hash + '.lock');
fs.mkdirSync(path.dirname(lockPath), { recursive: true });

if (fs.existsSync(lockPath)) {
  const stat = fs.statSync(lockPath);
  const staleMs = Date.now() - stat.mtimeMs;
  if (staleMs < 5 * 60 * 1000) {
    return [{ json: { locked: true } }];
  }
}

fs.writeFileSync(lockPath, String(Date.now()), 'utf8');
return [{ json: { locked: false, contact_hash: hash, project_prefix: $json.project_prefix, payload: $json.payload } }];

// Copies the validated, completed submission from public_html/intake_cache/
// into the protected Working\ path -- the one and only crossing point
// from public to backend (A9/A12).
const fs = require('fs');
const path = require('path');
const dest = path.join('Working', $json.project_prefix, 'intake_submissions', $json.contact_hash + '.json');
fs.mkdirSync(path.dirname(dest), { recursive: true });
fs.writeFileSync(dest, JSON.stringify($json.payload, null, 2), 'utf8');
return [{ json: $json }];
